import React from 'react';

/**
 * HeroCard Component
 * A versatile hero card component with background image, overlay text, and call-to-action button
 * 
 * Accessibility Features:
 * - Proper heading hierarchy (h2 instead of h1 to avoid multiple h1 elements)
 * - Button accessibility attributes (aria-label, title)
 * - Keyboard focus styles for navigation
 * - Enhanced text contrast for WCAG AA compliance
 * - Error handling for missing imageUrl
 */
const HeroCard = ({
  title,
  description,
  imageUrl,
  buttonText,
  buttonAction,
  badge,
  height = 'h-96',
  overlayOpacity = 'bg-black/50',
}) => {
  // Error handling: Validate required imageUrl prop
  if (!imageUrl || typeof imageUrl !== 'string' || imageUrl.trim() === '') {
    console.error('HeroCard: Required prop "imageUrl" is missing or invalid. Please provide a valid image URL.');
    return (
      <div className={`relative w-full ${height} overflow-hidden rounded-lg shadow-lg bg-gray-200 border-2 border-dashed border-gray-400`}>
        <div className="relative z-10 h-full flex flex-col justify-center items-center">
          <p className="text-gray-600 font-semibold text-center px-4">
            HeroCard: Missing or invalid imageUrl prop
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className={`relative w-full ${height} overflow-hidden rounded-lg shadow-lg`}>
      {/* Background Image */}
      <div
        className="absolute inset-0 bg-cover bg-center object-cover"
        style={{
          backgroundImage: `url(${imageUrl})`,
        }}
      />

      {/* Overlay */}
      <div className={`absolute inset-0 ${overlayOpacity} transition-opacity duration-300`} />

      {/* Content Container */}
      <div className="relative z-10 h-full flex flex-col justify-center items-start p-4 sm:p-8 md:p-12">
        {/* Badge (Optional) */}
        {badge && (
          <span className="inline-block bg-amber-500 text-white text-xs font-bold px-3 py-1 rounded-full mb-4">
            {badge}
          </span>
        )}

        {/* Title - Using h2 to maintain proper heading hierarchy */}
        <h2 className="text-3xl sm:text-4xl md:text-5xl font-bold text-white mb-4 leading-tight max-w-2xl">
          {title}
        </h2>

        {/* Description - Improved contrast: text-white for WCAG AA compliance */}
        {description && (
          <p className="text-base sm:text-lg md:text-xl text-white mb-6 max-w-xl">
            {description}
          </p>
        )}

        {/* Action Button - Enhanced accessibility */}
        {buttonText && (
          <button
            onClick={buttonAction}
            aria-label={`${buttonText}: ${title}`}
            title={`${buttonText}: ${title}`}
            className="bg-blue-600 hover:bg-blue-700 focus:ring-2 focus:ring-blue-400 focus:ring-offset-2 focus:outline-none text-white font-semibold px-6 py-3 rounded-lg transition-colors duration-200 active:bg-blue-800"
          >
            {buttonText}
          </button>
        )}
      </div>
    </div>
  );
};

export default HeroCard;

