import React, { useState } from 'react';
import Slider from '@/components/Slider';

export default function App() {
  const [singleValue, setSingleValue] = useState(50);
  const [priceValue, setPriceValue] = useState(75);
  const [disabledValue, setDisabledValue] = useState(30);

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 p-8">
      <div className="max-w-2xl mx-auto space-y-12">
        {/* Header */}
        <div>
          <h1 className="text-4xl font-bold text-gray-900 mb-2">Slider Component</h1>
          <p className="text-gray-600">Interactive range slider with keyboard and mouse support</p>
        </div>

        {/* Basic Slider */}
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold text-gray-800 mb-6">Basic Slider</h2>
          <Slider
            min={0}
            max={100}
            value={singleValue}
            onChange={setSingleValue}
            step={1}
            label="Select Value"
            showLabel={true}
          />
          <p className="mt-4 text-sm text-gray-600">
            Current value: <span className="font-semibold text-gray-900">{singleValue}</span>
          </p>
        </div>

        {/* Price Slider */}
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold text-gray-800 mb-6">Price Range Slider</h2>
          <Slider
            min={0}
            max={1000}
            value={priceValue}
            onChange={setPriceValue}
            step={10}
            label="Price"
            showLabel={true}
            className="mb-4"
          />
          <p className="text-sm text-gray-600">
            Selected price: <span className="font-semibold text-gray-900">${priceValue}</span>
          </p>
        </div>

        {/* Fine-tuned Slider */}
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold text-gray-800 mb-6">Fine-tuned Slider</h2>
          <Slider
            min={0}
            max={10}
            value={singleValue / 10}
            onChange={(val) => setSingleValue(val * 10)}
            step={0.1}
            label="Precision Control"
            showLabel={true}
          />
          <p className="mt-4 text-sm text-gray-600">
            Current value: <span className="font-semibold text-gray-900">{(singleValue / 10).toFixed(1)}</span>
          </p>
        </div>

        {/* Disabled Slider */}
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold text-gray-800 mb-6">Disabled Slider</h2>
          <Slider
            min={0}
            max={100}
            value={disabledValue}
            onChange={setDisabledValue}
            step={1}
            label="Disabled State"
            showLabel={true}
            disabled={true}
          />
          <p className="mt-4 text-sm text-gray-600">
            This slider is disabled and cannot be interacted with
          </p>
        </div>

        {/* Features */}
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-6">
          <h3 className="text-lg font-semibold text-blue-900 mb-4">Features</h3>
          <ul className="space-y-2 text-blue-800">
            <li className="flex items-start">
              <span className="mr-3">✓</span>
              <span>Mouse drag and click track to set value</span>
            </li>
            <li className="flex items-start">
              <span className="mr-3">✓</span>
              <span>Keyboard arrow keys for fine-tuning (Left/Right or Up/Down)</span>
            </li>
            <li className="flex items-start">
              <span className="mr-3">✓</span>
              <span>Customizable min, max, and step values</span>
            </li>
            <li className="flex items-start">
              <span className="mr-3">✓</span>
              <span>Optional value labels and disabled state</span>
            </li>
            <li className="flex items-start">
              <span className="mr-3">✓</span>
              <span>Fully accessible with keyboard navigation</span>
            </li>
            <li className="flex items-start">
              <span className="mr-3">✓</span>
              <span>Touch support for mobile devices</span>
            </li>
          </ul>
        </div>
      </div>
    </div>
  );
}

