import React, { useState, useRef, useEffect } from 'react';

export default function Slider({
  min = 0,
  max = 100,
  value = 0,
  onChange = () => {},
  step = 1,
  disabled = false,
  showLabel = true,
  label = '',
  className = '',
}) {
  const [isDragging, setIsDragging] = useState(false);
  const [isFocused, setIsFocused] = useState(false);
  const trackRef = useRef(null);
  const thumbRef = useRef(null);

  // Constrain value between min and max
  const constrainValue = (val) => {
    return Math.max(min, Math.min(max, val));
  };

  // Round value to step increments
  const roundToStep = (val) => {
    const steps = Math.round((val - min) / step);
    return min + steps * step;
  };

  // Handle value updates with rounding
  const updateValue = (newValue) => {
    const constrained = constrainValue(newValue);
    const rounded = roundToStep(constrained);
    onChange(rounded);
  };

  // Calculate percentage for positioning thumb
  const getPercentage = () => {
    if (max === min) return 0;
    return ((value - min) / (max - min)) * 100;
  };

  // Handle mouse/touch drag on thumb
  const handleMouseDown = (e) => {
    if (disabled) return;
    e.preventDefault();
    setIsDragging(true);
  };

  // Handle drag movement
  useEffect(() => {
    if (!isDragging || disabled) return;

    const handleMouseMove = (e) => {
      if (!trackRef.current) return;

      const rect = trackRef.current.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const percentage = Math.max(0, Math.min(1, x / rect.width));
      const newValue = min + percentage * (max - min);

      updateValue(newValue);
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, disabled, min, max]);

  // Handle track click to jump to position
  const handleTrackClick = (e) => {
    if (disabled) return;
    e.preventDefault();

    const rect = trackRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const percentage = Math.max(0, Math.min(1, x / rect.width));
    const newValue = min + percentage * (max - min);

    updateValue(newValue);
  };

  // Handle keyboard navigation
  const handleKeyDown = (e) => {
    if (disabled) return;

    let newValue = value;

    switch (e.key) {
      case 'ArrowLeft':
      case 'ArrowDown':
        e.preventDefault();
        newValue = value - step;
        break;
      case 'ArrowRight':
      case 'ArrowUp':
        e.preventDefault();
        newValue = value + step;
        break;
      case 'Home':
        e.preventDefault();
        newValue = min;
        break;
      case 'End':
        e.preventDefault();
        newValue = max;
        break;
      default:
        return;
    }

    updateValue(newValue);
  };

  const percentage = getPercentage();

  return (
    <div className={`flex flex-col gap-3 ${className}`}>
      {/* Label Row */}
      {label && (
        <div className="flex justify-between items-center">
          <label className="text-sm font-medium text-gray-700">{label}</label>
        </div>
      )}

      {/* Slider Container */}
      <div className="flex items-center gap-3 px-2 py-4">
        {/* Track and Thumb */}
        <div className="flex-1 relative">
          {/* Track Background */}
          <div
            ref={trackRef}
            onClick={handleTrackClick}
            className={`absolute top-1/2 left-0 right-0 h-1 bg-gray-200 rounded transform -translate-y-1/2 cursor-pointer ${
              disabled ? 'opacity-50 cursor-not-allowed' : ''
            }`}
          >
            {/* Filled Track */}
            <div
              className={`h-full bg-blue-500 rounded transition-all ${
                disabled ? 'opacity-50' : ''
              }`}
              style={{ width: `${percentage}%` }}
            />
          </div>

          {/* Thumb (Handle) */}
          <button
            ref={thumbRef}
            onMouseDown={handleMouseDown}
            onTouchStart={handleMouseDown}
            onKeyDown={handleKeyDown}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            tabIndex={disabled ? -1 : 0}
            disabled={disabled}
            aria-label={label || 'Slider'}
            aria-valuemin={min}
            aria-valuemax={max}
            aria-valuenow={value}
            className={`absolute top-1/2 w-5 h-5 bg-blue-500 rounded-full transform -translate-y-1/2 -translate-x-1/2 shadow-md transition-all ${
              isDragging || isFocused ? 'ring-2 ring-blue-400' : ''
            } ${disabled ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-600 cursor-grab active:cursor-grabbing'}`}
            style={{
              left: `${percentage}%`,
              zIndex: isDragging ? 50 : 10,
            }}
          >
            {/* Value Tooltip */}
            {showLabel && (
              <div
                className={`absolute bottom-full left-1/2 transform -translate-x-1/2 mb-2 px-2 py-1 bg-gray-900 text-white text-xs font-medium rounded whitespace-nowrap pointer-events-none transition-opacity ${
                  isDragging || isFocused ? 'opacity-100' : 'opacity-0'
                }`}
              >
                {value}
              </div>
            )}
          </button>
        </div>
      </div>

      {/* Value Display */}
      {showLabel && (
        <div className="text-xs text-gray-500 px-2">
          {min} — {max}
        </div>
      )}
    </div>
  );
}

