import React, { useState } from 'react';
import TreeView from '@/components/TreeView';

export default function App() {
  const [selectedNodeId, setSelectedNodeId] = useState(null);
  const [expandedNodeIds, setExpandedNodeIds] = useState(new Set(['root', 'folder1']));

  // Sample hierarchical data
  const treeData = [
    {
      id: 'root',
      label: 'Documents',
      children: [
        {
          id: 'folder1',
          label: 'Projects',
          children: [
            {
              id: 'project1',
              label: 'React App',
              children: [
                { id: 'file1', label: 'index.jsx', isLeaf: true },
                { id: 'file2', label: 'App.jsx', isLeaf: true },
                { id: 'file3', label: 'styles.css', isLeaf: true },
              ],
            },
            {
              id: 'project2',
              label: 'Vue App',
              children: [
                { id: 'file4', label: 'main.js', isLeaf: true },
                { id: 'file5', label: 'App.vue', isLeaf: true },
              ],
            },
          ],
        },
        {
          id: 'folder2',
          label: 'Archive',
          children: [
            { id: 'file6', label: 'backup.zip', isLeaf: true },
            { id: 'file7', label: 'old_project.tar', isLeaf: true },
          ],
        },
        {
          id: 'file8',
          label: 'ReadMe.md',
          isLeaf: true,
        },
      ],
    },
  ];

  const handleNodeSelect = (nodeId) => {
    setSelectedNodeId(nodeId);
  };

  const handleToggleExpand = (nodeId) => {
    const newExpandedNodeIds = new Set(expandedNodeIds);
    if (newExpandedNodeIds.has(nodeId)) {
      newExpandedNodeIds.delete(nodeId);
    } else {
      newExpandedNodeIds.add(nodeId);
    }
    setExpandedNodeIds(newExpandedNodeIds);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-50 p-8">
      <div className="max-w-2xl mx-auto">
        <div className="bg-white rounded-lg shadow-lg p-6">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">Tree View Component</h1>
          <p className="text-gray-600 mb-6">Click to expand/collapse folders and select nodes</p>

          <div className="border border-gray-200 rounded-lg bg-gray-50 p-4">
            <TreeView
              data={treeData}
              onNodeSelect={handleNodeSelect}
              selectedNodeId={selectedNodeId}
              expandedNodeIds={expandedNodeIds}
              onToggleExpand={handleToggleExpand}
              showIcons={true}
            />
          </div>

          {selectedNodeId && (
            <div className="mt-6 p-4 bg-blue-50 border border-blue-200 rounded-lg">
              <p className="text-sm font-semibold text-gray-600">Selected Node ID:</p>
              <p className="text-lg font-mono text-blue-600 mt-1">{selectedNodeId}</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import TreeNode from '@/components/TreeNode';

/**
 * TreeView Component
 * 
 * A hierarchical tree view component that displays nested data structures
 * with expand/collapse functionality and selection support.
 * 
 * @component
 * @param {Object} props
 * @param {Array} props.data - Array of root-level tree nodes
 * @param {Function} props.onNodeSelect - Callback when node is selected
 * @param {string|null} props.selectedNodeId - Currently selected node ID
 * @param {Set} props.expandedNodeIds - Set of expanded node IDs
 * @param {Function} props.onToggleExpand - Callback to expand/collapse
 * @param {boolean} [props.showIcons=true] - Show folder/file icons
 * @returns {React.ReactElement}
 */
export default function TreeView({
  data,
  onNodeSelect,
  selectedNodeId,
  expandedNodeIds,
  onToggleExpand,
  showIcons = true,
}) {
  return (
    <div className="flex flex-col gap-1">
      {data.map((node) => (
        <TreeNode
          key={node.id}
          node={node}
          level={0}
          isExpanded={expandedNodeIds.has(node.id)}
          isSelected={selectedNodeId === node.id}
          onToggleExpand={onToggleExpand}
          onSelect={onNodeSelect}
          showIcons={showIcons}
        />
      ))}
    </div>
  );
}

import React from 'react';
import { ChevronRight, Folder, FileText } from 'lucide-react';

/**
 * TreeNode Component
 * 
 * A recursive component that renders individual tree nodes with
 * expand/collapse and selection functionality.
 * 
 * @component
 * @param {Object} props
 * @param {Object} props.node - Node data object with id, label, children, isLeaf
 * @param {number} props.level - Nesting depth for indentation
 * @param {boolean} props.isExpanded - Whether this node is expanded
 * @param {boolean} props.isSelected - Whether this node is selected
 * @param {Function} props.onToggleExpand - Expand/collapse handler
 * @param {Function} props.onSelect - Selection handler
 * @param {boolean} props.showIcons - Show folder/file icons
 * @returns {React.ReactElement}
 */
export default function TreeNode({
  node,
  level,
  isExpanded,
  isSelected,
  onToggleExpand,
  onSelect,
  showIcons,
}) {
  const hasChildren = node.children && node.children.length > 0;
  const isLeaf = node.isLeaf || !hasChildren;

  // Indent based on nesting level
  const indentClass = level > 0 ? `ml-${Math.min(level * 4, 16)}` : '';

  // Determine icon to display
  const getIcon = () => {
    if (!showIcons) return null;

    if (node.icon) {
      return node.icon;
    }

    if (isLeaf) {
      return <FileText className="w-4 h-4 text-gray-400" />;
    }

    return <Folder className="w-4 h-4 text-gray-500" />;
  };

  const handleExpandClick = (e) => {
    e.stopPropagation();
    onToggleExpand(node.id);
  };

  const handleNodeClick = () => {
    onSelect(node.id);
  };

  return (
    <div className="flex flex-col">
      {/* Node Header */}
      <div
        className={`
          flex items-center gap-2 px-2 py-1 rounded cursor-pointer
          transition-colors duration-150 ease-in-out
          ${level > 0 ? `ml-${Math.min(level * 4, 16)}` : ''}
          ${
            isSelected
              ? 'bg-blue-50 text-blue-600'
              : 'text-gray-700 hover:bg-gray-100 hover:text-gray-900'
          }
        `}
        onClick={handleNodeClick}
        role="treeitem"
        aria-expanded={hasChildren ? isExpanded : undefined}
        tabIndex={0}
      >
        {/* Expand/Collapse Icon */}
        {hasChildren ? (
          <button
            onClick={handleExpandClick}
            className={`
              flex-shrink-0 p-0 flex items-center justify-center
              transition-transform duration-200 ease-in-out
              ${isExpanded ? 'rotate-90' : ''}
            `}
            aria-label={isExpanded ? 'Collapse' : 'Expand'}
          >
            <ChevronRight className="w-4 h-4" />
          </button>
        ) : (
          <div className="w-4 h-4 flex-shrink-0" />
        )}

        {/* Node Icon */}
        {getIcon() && <div className="flex-shrink-0">{getIcon()}</div>}

        {/* Node Label */}
        <span className="flex-1 text-sm font-medium truncate">{node.label}</span>
      </div>

      {/* Node Children - Rendered Recursively */}
      {hasChildren && isExpanded && (
        <div className="flex flex-col">
          {node.children.map((childNode) => (
            <TreeNode
              key={childNode.id}
              node={childNode}
              level={level + 1}
              isExpanded={node._expandedChildren?.has(childNode.id) || false}
              isSelected={false}
              onToggleExpand={onToggleExpand}
              onSelect={onSelect}
              showIcons={showIcons}
            />
          ))}
        </div>
      )}
    </div>
  );
}

/** @type {import('tailwindcss').Config} */
export default {
  content: [
    "./index.html",
    "./App.jsx",
    "./components/**/*.{js,jsx,ts,tsx}",
  ],
  theme: {
    extend: {
      spacing: {
        'ml-4': '1rem',
        'ml-8': '2rem',
        'ml-12': '3rem',
        'ml-16': '4rem',
      },
    },
  },
  plugins: [],
}

