        return 'ml-8';
      case 3:
        return 'ml-12';
      case 4:
        return 'ml-16';
      default:
        return level > 0 ? `ml-[${level * 16}px]` : '';
    }
  };

  // Determine icon to display
  const getIcon = () => {
    if (!showIcons) return null;

    if (node.icon) {
