import React from 'react';
import { ChevronRight, Folder, FileText } from 'lucide-react';

/**
 * TreeNode Component
 * 
 * A recursive component that renders individual tree nodes with
 * expand/collapse and selection functionality.
 * 
 * @component
 * @param {Object} props
 * @param {Object} props.node - Node data object with id, label, children, isLeaf
 * @param {number} props.level - Nesting depth for indentation
 * @param {Set} props.expandedNodeIds - Set of all expanded node IDs from parent
 * @param {string|null} props.selectedNodeId - Currently selected node ID from parent
 * @param {Function} props.onToggleExpand - Expand/collapse handler
 * @param {Function} props.onSelect - Selection handler
 * @param {boolean} props.showIcons - Show folder/file icons
 * @returns {React.ReactElement}
 */
export default function TreeNode({
  node,
  level,
  expandedNodeIds,
  selectedNodeId,
  onToggleExpand,
  onSelect,
  showIcons,
}) {
  const hasChildren = node.children && node.children.length > 0;
  const isLeaf = node.isLeaf || !hasChildren;
  const isExpanded = expandedNodeIds.has(node.id);
  const isSelected = selectedNodeId === node.id;

  // Get indent class based on nesting level
  // Only use predefined Tailwind classes to ensure proper styling
  const getIndentClass = () => {
    switch (level) {
      case 0:
        return 'ml-0';
      case 1:
        return 'ml-4';
      case 2:
        return 'ml-8';
      case 3:
        return 'ml-12';
      case 4:
        return 'ml-16';
      case 5:
        return 'ml-20';
      case 6:
        return 'ml-24';
      default:
        // For deeper levels, fall back to a higher predefined level
        return 'ml-24';
    }
  };

  // Determine icon to display
  const getIcon = () => {
    if (!showIcons) return null;

    if (node.icon) {
      return node.icon;
    }

    if (isLeaf) {
      return <FileText className="w-4 h-4 text-gray-400" />;
    }

    return <Folder className="w-4 h-4 text-gray-500" />;
  };

  const handleExpandClick = (e) => {
    e.stopPropagation();
    onToggleExpand(node.id);
  };

  const handleNodeClick = () => {
    onSelect(node.id);
  };

  const indentClass = getIndentClass();

  return (
    <div className="flex flex-col">
      {/* Indentation Wrapper - Handles level-based indentation */}
      <div className={`flex flex-col ${indentClass}`}>
        {/* Node Header - Inner container for node styling */}
        <div
          className={`
            flex items-center gap-2 px-2 py-1 rounded cursor-pointer
            transition-colors duration-150 ease-in-out
            ${
              isSelected
                ? 'bg-blue-50 text-blue-600'
                : 'text-gray-700 hover:bg-gray-100 hover:text-gray-900'
            }
          `}
          onClick={handleNodeClick}
          role="treeitem"
          aria-expanded={hasChildren ? isExpanded : undefined}
          tabIndex={0}
        >
          {/* Expand/Collapse Icon */}
          {hasChildren ? (
            <button
              onClick={handleExpandClick}
              className={`
                flex-shrink-0 p-0 flex items-center justify-center
                transition-transform duration-200 ease-in-out
                ${isExpanded ? 'rotate-90' : ''}
              `}
              aria-label={isExpanded ? 'Collapse' : 'Expand'}
              aria-pressed={isExpanded}
              type="button"
            >
              <ChevronRight className="w-4 h-4" />
            </button>
          ) : (
            <div className="w-4 h-4 flex-shrink-0" />
          )}

          {/* Node Icon */}
          {getIcon() && <div className="flex-shrink-0">{getIcon()}</div>}

          {/* Node Label */}
          <span className="flex-1 text-sm font-medium truncate">{node.label}</span>
        </div>
      </div>

      {/* Node Children - Rendered Recursively */}
      {hasChildren && isExpanded && (
        <div className="flex flex-col">
          {node.children.map((childNode) => (
            <TreeNode
              key={childNode.id}
              node={childNode}
              level={level + 1}
              expandedNodeIds={expandedNodeIds}
              selectedNodeId={selectedNodeId}
              onToggleExpand={onToggleExpand}
              onSelect={onSelect}
              showIcons={showIcons}
            />
          ))}
        </div>
      )}
    </div>
  );
}

