import React, { useState } from 'react';
import Button from '@/components/Button';

export default function App() {
  const [clickCount, setClickCount] = useState(0);
  const [lastClicked, setLastClicked] = useState(null);
  const [feedback, setFeedback] = useState('');

  const handleButtonClick = (variant) => {
    setClickCount(clickCount + 1);
    setLastClicked(variant);
    setFeedback(`Clicked: ${variant}`);
    // Auto-clear feedback after 2 seconds
    setTimeout(() => setFeedback(''), 2000);
  };

  return (
    <div className="min-h-screen bg-slate-50 p-8">
      <div className="max-w-6xl mx-auto">
        <h1 className="text-4xl font-bold text-slate-900 mb-2">Button Component</h1>
        <p className="text-slate-600 mb-12">A reusable, accessible button component with multiple variants and sizes — iOS inspired</p>

        {/* Primary Variant */}
        <div className="mb-12">
          <h2 className="text-2xl font-semibold text-slate-900 mb-4">Primary</h2>
          <div className="flex flex-wrap gap-4 p-6 bg-white rounded-2xl border border-slate-200">
            <Button label="Small" variant="primary" size="sm" onClick={() => handleButtonClick('Primary Small')} />
            <Button label="Medium" variant="primary" size="md" onClick={() => handleButtonClick('Primary Medium')} />
            <Button label="Large" variant="primary" size="lg" onClick={() => handleButtonClick('Primary Large')} />
            <Button label="Disabled" variant="primary" disabled />
          </div>
        </div>

        {/* Secondary Variant */}
        <div className="mb-12">
          <h2 className="text-2xl font-semibold text-slate-900 mb-4">Secondary</h2>
          <div className="flex flex-wrap gap-4 p-6 bg-white rounded-2xl border border-slate-200">
            <Button label="Small" variant="secondary" size="sm" onClick={() => handleButtonClick('Secondary Small')} />
            <Button label="Medium" variant="secondary" size="md" onClick={() => handleButtonClick('Secondary Medium')} />
            <Button label="Large" variant="secondary" size="lg" onClick={() => handleButtonClick('Secondary Large')} />
            <Button label="Disabled" variant="secondary" disabled />
          </div>
        </div>

        {/* Outline Variant */}
        <div className="mb-12">
          <h2 className="text-2xl font-semibold text-slate-900 mb-4">Outline</h2>
          <div className="flex flex-wrap gap-4 p-6 bg-white rounded-2xl border border-slate-200">
            <Button label="Small" variant="outline" size="sm" onClick={() => handleButtonClick('Outline Small')} />
            <Button label="Medium" variant="outline" size="md" onClick={() => handleButtonClick('Outline Medium')} />
            <Button label="Large" variant="outline" size="lg" onClick={() => handleButtonClick('Outline Large')} />
            <Button label="Disabled" variant="outline" disabled />
          </div>
        </div>

        {/* Danger Variant */}
        <div className="mb-12">
          <h2 className="text-2xl font-semibold text-slate-900 mb-4">Danger</h2>
          <div className="flex flex-wrap gap-4 p-6 bg-white rounded-2xl border border-slate-200">
            <Button label="Small" variant="danger" size="sm" onClick={() => handleButtonClick('Danger Small')} />
            <Button label="Medium" variant="danger" size="md" onClick={() => handleButtonClick('Danger Medium')} />
            <Button label="Large" variant="danger" size="lg" onClick={() => handleButtonClick('Danger Large')} />
            <Button label="Disabled" variant="danger" disabled />
          </div>
        </div>

        {/* Interaction Demo */}
        <div className="p-6 bg-white rounded-2xl border border-slate-200">
          <h2 className="text-2xl font-semibold text-slate-900 mb-4">Interaction Demo</h2>
          <div className="space-y-4">
            <div className="flex gap-4 flex-wrap">
              <Button 
                label="Click Me" 
                variant="primary"
                onClick={() => handleButtonClick('Demo Button')}
              />
              <Button 
                label="Try Tab Navigation" 
                variant="secondary"
                onClick={() => handleButtonClick('Keyboard Navigation')}
              />
            </div>
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-200">
              <p className="text-slate-700 mb-2">
                <span className="font-semibold">Total Clicks:</span> <span className="text-blue-600 text-lg">{clickCount}</span>
              </p>
              {lastClicked && (
                <p className="text-slate-700 mb-2">
                  <span className="font-semibold">Last Clicked:</span> <span className="text-blue-600">{lastClicked}</span>
                </p>
              )}
              {feedback && (
                <div className="mt-3 p-3 bg-blue-50 border border-blue-200 rounded-lg text-blue-700 font-medium">
                  ✓ {feedback}
                </div>
              )}
            </div>
            <div className="p-4 bg-blue-50 rounded-lg border border-blue-200">
              <p className="text-sm text-blue-900">
                <span className="font-semibold">Accessibility Features:</span> Press Tab to navigate between buttons. Focus ring is visible on all buttons for keyboard accessibility. Disabled buttons cannot be clicked and are not reachable via keyboard.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

