import Accordion from '@/components/Accordion';

export default function App() {
  const items = [
    {
      id: '1',
      title: 'What is React?',
      content:
        'React is a JavaScript library for building user interfaces with reusable components. It uses a virtual DOM for efficient rendering and provides a declarative way to build interactive UIs.',
    },
    {
      id: '2',
      title: 'What is Tailwind CSS?',
      content:
        'Tailwind CSS is a utility-first CSS framework that helps you build modern designs without leaving your HTML. It provides a comprehensive set of pre-built utility classes for styling.',
    },
    {
      id: '3',
      title: 'How does this accordion work?',
      content:
        'This accordion component manages state in the parent Accordion component and allows you to toggle visibility of content sections. You can choose to allow multiple sections open at once or restrict to a single open item.',
    },
    {
      id: '4',
      title: 'Is it accessible?',
      content:
        'Yes! This accordion includes proper ARIA attributes (aria-expanded, aria-controls), semantic HTML, keyboard navigation support, and focus visible states for accessibility compliance.',
    },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 py-12 px-4">
      <div className="max-w-2xl mx-auto">
        <div className="mb-8">
          <h1 className="text-4xl font-bold text-gray-900 mb-2">Accordion Component</h1>
          <p className="text-gray-600">
            A fully accessible, animated accordion component built with React and Tailwind CSS
          </p>
        </div>

        <div className="mb-8">
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Single Open (Default)</h2>
          <Accordion items={items} allowMultiple={false} />
        </div>

        <div>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Multiple Open Allowed</h2>
          <Accordion items={items} allowMultiple={true} />
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import AccordionItem from './AccordionItem';

export default function Accordion({ items = [], allowMultiple = false }) {
  const [openItems, setOpenItems] = useState(new Set());

  const handleToggle = (itemId) => {
    setOpenItems((prevOpenItems) => {
      const newOpenItems = new Set(prevOpenItems);

      if (newOpenItems.has(itemId)) {
        // Close the item
        newOpenItems.delete(itemId);
      } else {
        // Open the item
        if (!allowMultiple) {
          // If multiple not allowed, close all other items
          newOpenItems.clear();
        }
        newOpenItems.add(itemId);
      }

      return newOpenItems;
    });
  };

  return (
    <div className="border border-gray-200 rounded-lg shadow-sm bg-white overflow-hidden">
      {items.map((item, index) => (
        <AccordionItem
          key={item.id}
          id={item.id}
          title={item.title}
          content={item.content}
          isOpen={openItems.has(item.id)}
          onToggle={handleToggle}
          isLast={index === items.length - 1}
        />
      ))}
    </div>
  );
}

import AccordionHeader from './AccordionHeader';
import AccordionContent from './AccordionContent';

export default function AccordionItem({
  id,
  title,
  content,
  isOpen,
  onToggle,
  isLast = false,
}) {
  return (
    <div className={!isLast ? 'border-b border-gray-200' : ''}>
      <AccordionHeader
        id={id}
        title={title}
        isOpen={isOpen}
        onClick={() => onToggle(id)}
      />
      <AccordionContent isOpen={isOpen} id={id}>
        {content}
      </AccordionContent>
    </div>
  );
}

export default function AccordionHeader({ id, title, isOpen, onClick }) {
  return (
    <button
      id={`accordion-trigger-${id}`}
      aria-expanded={isOpen}
      aria-controls={`accordion-content-${id}`}
      onClick={onClick}
      className="w-full px-6 py-4 flex items-center justify-between font-semibold text-gray-900 hover:bg-gray-50 cursor-pointer transition-colors duration-200 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-500"
