import React, { useState, useCallback } from 'react';

const AccordionContext = React.createContext();

export const useAccordion = () => {
  const context = React.useContext(AccordionContext);
  if (!context) {
    throw new Error('useAccordion must be used within an AccordionContainer');
  }
  return context;
};

export default function AccordionContainer({
  children,
  type = 'single',
  className = '',
}) {
  const [openItems, setOpenItems] = useState(new Set());

  const toggleItem = useCallback((value) => {
    setOpenItems((prevOpen) => {
      const newOpen = new Set(prevOpen);

      if (type === 'single') {
        // Single mode: close all others and toggle the current one
        if (newOpen.has(value)) {
          newOpen.delete(value);
        } else {
          newOpen.clear();
          newOpen.add(value);
        }
      } else {
        // Multiple mode: toggle the current item independently
        if (newOpen.has(value)) {
          newOpen.delete(value);
        } else {
          newOpen.add(value);
        }
      }

      return newOpen;
    });
  }, [type]);

  const isOpen = useCallback((value) => {
    return openItems.has(value);
  }, [openItems]);

  const contextValue = {
    openItems,
    toggleItem,
    isOpen,
    type,
  };

  return (
    <AccordionContext.Provider value={contextValue}>
      <div
        className={`border border-gray-200 rounded-lg overflow-hidden divide-y divide-gray-200 ${className}`}
      >
        {children}
      </div>
    </AccordionContext.Provider>
  );
}

