}

import React from 'react';
import { useAccordion } from './AccordionContainer';
import { useAccordionItem } from './AccordionItem';

export default function AccordionTrigger({
  children,
  className = '',
}) {
  const { toggleItem, isOpen } = useAccordion();
  const { value, disabled } = useAccordionItem();
  const open = isOpen(value);

  const handleClick = () => {
    if (!disabled) {
      toggleItem(value);
    }
  };

  const handleKeyDown = (e) => {
    if (disabled) return;

    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      toggleItem(value);
    }
  };

  return (
    <button
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      disabled={disabled}
      className={`
        w-full px-6 py-4 flex items-center justify-between
        font-medium text-base text-gray-900
        bg-white hover:bg-gray-50 active:bg-gray-100
        transition-colors duration-200
        ${open ? 'bg-blue-50' : ''}
        ${disabled ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}
        focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-500 focus-visible:ring-offset-0
        ${className}
      `}
      aria-expanded={open}
      aria-controls={`content-${value}`}
    >
      <span>{children}</span>
      <ChevronIcon open={open} />
    </button>
  );
}

