import React, { useState } from 'react';
import Button from '@/components/Button';

export default function ButtonGroup({
  orientation = 'horizontal',
  size = 'md',
  variant = 'solid',
  color = 'blue',
  selectionMode = 'none',
  children,
  value: controlledValue,
  onChange,
  disabled = false,
}) {
  const [internalValue, setInternalValue] = useState(
    selectionMode === 'multiple' ? [] : ''
  );

  const isControlled = controlledValue !== undefined;
  const selectedValue = isControlled ? controlledValue : internalValue;

  const handleButtonClick = (buttonValue) => {
    if (disabled) return;

    let newValue;

    if (selectionMode === 'single') {
      newValue = selectedValue === buttonValue ? '' : buttonValue;
    } else if (selectionMode === 'multiple') {
      const selected = Array.isArray(selectedValue) ? selectedValue : [];
      newValue = selected.includes(buttonValue)
        ? selected.filter((v) => v !== buttonValue)
        : [...selected, buttonValue];
    } else {
      return; // 'none' mode - no selection
    }

    if (!isControlled) {
      setInternalValue(newValue);
    }

    if (onChange) {
      onChange(newValue);
    }
  };

  const containerClasses = `inline-flex rounded-lg overflow-hidden border ${
    orientation === 'horizontal' ? 'flex-row' : 'flex-col'
  } gap-0 ${disabled ? 'opacity-50 cursor-not-allowed' : ''} border-gray-300`;

  return (
    <div className={containerClasses}>
      {React.Children.map(children, (child, index) => {
        if (!child || !React.isValidElement(child)) return null;

        const isActive =
          selectionMode === 'single'
            ? selectedValue === child.props.value
            : selectionMode === 'multiple'
            ? (Array.isArray(selectedValue) ? selectedValue : []).includes(
                child.props.value
              )
            : false;

        const isLastChild = index === React.Children.count(children) - 1;
        const borderClass =
          orientation === 'horizontal' && !isLastChild ? 'border-r' : '';
        const verticalBorderClass =
          orientation === 'vertical' && !isLastChild ? 'border-b' : '';

        return React.cloneElement(child, {
          key: child.props.value || index,
          size,
          variant,
          color,
          isActive,
          disabled: disabled || child.props.disabled,
          onClick: () => handleButtonClick(child.props.value),
          borderClass: `${borderClass} ${verticalBorderClass} border-gray-300`,
        });
      })}
    </div>
  );
}

ButtonGroup.Button = Button;

import React from 'react';

export default function Button({
  value,
  children,
  icon,
  disabled = false,
  isActive = false,
  onClick,
  size = 'md',
  variant = 'solid',
  color = 'blue',
  borderClass = '',
}) {
  // Size classes
  const sizeClasses = {
    sm: 'px-3 py-1 text-sm',
    md: 'px-4 py-2 text-base',
    lg: 'px-6 py-3 text-lg',
  };

  // Solid variant classes
  const solidClasses = {
    blue: {
      active: 'bg-blue-600 text-white',
      inactive: 'bg-gray-200 text-gray-700 hover:bg-gray-300',
    },
    gray: {
      active: 'bg-gray-700 text-white',
      inactive: 'bg-gray-100 text-gray-700 hover:bg-gray-200',
    },
    green: {
      active: 'bg-green-600 text-white',
      inactive: 'bg-gray-200 text-gray-700 hover:bg-gray-300',
    },
    red: {
      active: 'bg-red-600 text-white',
      inactive: 'bg-gray-200 text-gray-700 hover:bg-gray-300',
    },
  };

  // Outline variant classes
  const outlineClasses = {
    blue: {
      active: 'bg-blue-50 border-blue-600 text-blue-600',
      inactive: 'bg-white border-gray-300 text-gray-700 hover:border-gray-400',
    },
    gray: {
      active: 'bg-gray-50 border-gray-700 text-gray-700',
      inactive: 'bg-white border-gray-300 text-gray-700 hover:border-gray-400',
    },
    green: {
      active: 'bg-green-50 border-green-600 text-green-600',
      inactive: 'bg-white border-gray-300 text-gray-700 hover:border-gray-400',
    },
    red: {
      active: 'bg-red-50 border-red-600 text-red-600',
      inactive: 'bg-white border-gray-300 text-gray-700 hover:border-gray-400',
    },
  };

  // Get color classes based on variant
  const colorMap =
    variant === 'solid' ? solidClasses[color] : outlineClasses[color];
  const stateClasses = isActive ? colorMap.active : colorMap.inactive;

  // Outline variant needs border styling
  const outlineBorderClass =
    variant === 'outline'
      ? isActive
        ? `border border-${color}-600`
        : 'border border-gray-300'
      : '';

  // Combine all classes
  const buttonClasses = `
    ${sizeClasses[size]}
    ${stateClasses}
    ${outlineBorderClass}
    ${borderClass}
    rounded-none
    font-medium
    transition-colors
    duration-200
    ease-in-out
    cursor-pointer
    inline-flex
    items-center
    justify-center
    gap-2
    whitespace-nowrap
    ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
  `.trim();

  return (
    <button
      className={buttonClasses}
      onClick={onClick}
      disabled={disabled}
      value={value}
    >
      {icon && <span className="flex items-center">{icon}</span>}
      {children}
    </button>
  );
}

