  const solidInactiveClasses = {
    blue: 'bg-gray-200 text-gray-700 hover:bg-gray-300',
    gray: 'bg-gray-100 text-gray-700 hover:bg-gray-200',
    green: 'bg-gray-200 text-gray-700 hover:bg-gray-300',
    red: 'bg-gray-200 text-gray-700 hover:bg-gray-300',
  };

  // Outline variant classes - active states (with explicit border colors)
  const outlineActiveClasses = {
    blue: 'bg-blue-50 border border-blue-600 text-blue-600',
    gray: 'bg-gray-50 border border-gray-700 text-gray-700',
    green: 'bg-green-50 border border-green-600 text-green-600',
    red: 'bg-red-50 border border-red-600 text-red-600',
  };

  // Outline variant classes - inactive states
  const outlineInactiveClasses = {
    blue: 'bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 hover:border-gray-400',
    gray: 'bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 hover:border-gray-400',
    green: 'bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 hover:border-gray-400',
    red: 'bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 hover:border-gray-400',
  };

  // Get color classes based on variant and state
  let colorClasses = '';
  if (variant === 'solid') {
    colorClasses = isActive ? solidActiveClasses[color] : solidInactiveClasses[color];
  } else {
    colorClasses = isActive ? outlineActiveClasses[color] : outlineInactiveClasses[color];
  }

  // Determine which border class to use (avoid double border if outline already has it)
  let finalBorderClass = borderClass;
  if (variant === 'outline') {
    // Remove 'border' from borderClass if present since outline variant includes it
    finalBorderClass = borderClass
      .replace(/border(?!\w)/g, '')
      .replace(/border-gray-300/g, '')
      .trim();
  }

  // Combine all classes
  const buttonClasses = `
    ${sizeClasses[size]}
    ${colorClasses}
    ${finalBorderClass}
    rounded-none
    font-medium
    transition-colors
    duration-200
    ease-in-out
    inline-flex
    items-center
    justify-center
    gap-2
    whitespace-nowrap
    ${disabled ? 'opacity-60 cursor-not-allowed pointer-events-none' : 'cursor-pointer hover:transition-colors'}
  `.trim();

  // Determine aria attributes based on selection mode
  const ariaAttributes = {};

  if (selectionMode === 'single') {
    ariaAttributes['aria-selected'] = isActive;
    ariaAttributes['aria-pressed'] = false;
  } else if (selectionMode === 'multiple') {
    ariaAttributes['aria-pressed'] = isActive;
    ariaAttributes['aria-selected'] = false;
  }

  return (
    <button
      className={buttonClasses}
      onClick={onClick}
      disabled={disabled}
      value={value}
      {...ariaAttributes}
    >
      {icon && <span className="flex items-center">{icon}</span>}
      {children}
    </button>
  );
}

