      aria-disabled={disabled}
    >
      {React.Children.map(children, (child, index) => {
        if (!child || !React.isValidElement(child)) return null;

        const isActive =
          selectionMode === 'single'
            ? selectedValue === child.props.value
            : selectionMode === 'multiple'
            ? (Array.isArray(selectedValue) ? selectedValue : []).includes(
                child.props.value
              )
            : false;

        const isLastChild = index === React.Children.count(children) - 1;

        // Build border class - only add separator borders for solid variant
        let borderClass = '';
        if (variant === 'solid') {
          if (orientation === 'horizontal' && !isLastChild) {
            borderClass = 'border-r border-gray-300';
          } else if (orientation === 'vertical' && !isLastChild) {
            borderClass = 'border-b border-gray-300';
          }
        } else if (variant === 'outline' && !isLastChild) {
          // For outline variant, no internal borders since each button has its own
          borderClass = '';
        }

        return React.cloneElement(child, {
          key: child.props.value || index,
          size,
          variant,
          color,
          selectionMode,
          isActive,
          disabled: disabled || child.props.disabled,
          onClick: () => handleButtonClick(child.props.value),
          borderClass,
        });
      })}
    </div>
  );
}

